* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  background: #F4F6F8;
}

.widget-wrap {
  background: #fff;
  border: 1px solid #e2e8f0;
  border-radius: 10px;
  overflow: hidden;
}

.toolbar {
  padding: 10px 14px;
  border-bottom: 1px solid #e2e8f0;
  background: #fff;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.search-row {
  display: flex;
  align-items: center;
  gap: 8px;
  background: #F4F6F8;
  border: 1px solid #e2e8f0;
  border-radius: 6px;
  padding: 6px 10px;
}

.search-row input {
  flex: 1;
  border: none;
  background: transparent;
  font-size: 13px;
  color: #1e293b;
  outline: none;
}

.search-row input::placeholder {
  color: #94a3b8;
}

.filter-pills {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.pill {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  padding: 4px 10px;
  border-radius: 20px;
  font-size: 12px;
  font-weight: 500;
  cursor: pointer;
  border: 1px solid #e2e8f0;
  background: #f8fafc;
  color: #64748b;
  transition: all 0.12s;
  user-select: none;
  white-space: nowrap;
}

.pill:hover {
  border-color: #cbd5e1;
  background: #f1f5f9;
}

.pill .cnt {
  background: rgba(0, 0, 0, 0.08);
  border-radius: 20px;
  padding: 0 5px;
  font-size: 11px;
  line-height: 16px;
}

.pill.active-all {
  background: #1A2E3B;
  color: #fff;
  border-color: #1A2E3B;
}

.pill.active-all .cnt {
  background: rgba(255, 255, 255, 0.2);
}

.pill.active-yes {
  background: #dcfce7;
  color: #15803d;
  border-color: #bbf7d0;
}

.pill.active-pending {
  background: #fef3c7;
  color: #92400e;
  border-color: #fde68a;
}

.pill.active-no {
  background: #fee2e2;
  color: #991b1b;
  border-color: #fecaca;
}

.table-scroll {
  overflow-x: auto;
}

table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
}

col.col-customer {
  width: 18%;
}

col.col-dialref {
  width: 10%;
}

col.col-expiry {
  width: 14%;
}

col.col-msa {
  width: 12%;
}

col.col-created {
  width: 12%;
}

col.col-manager {
  width: 18%;
}

col.col-view {
  width: 10%;
}

thead tr {
  background: #F4F6F8;
}

th {
  padding: 9px 14px;
  font-size: 11px;
  font-weight: 600;
  color: #64748b;
  text-align: left;
  border-bottom: 1px solid #e2e8f0;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  white-space: nowrap;
}

th.th-view {
  text-align: center;
}

td {
  padding: 10px 14px;
  font-size: 13px;
  color: #1e293b;
  border-bottom: 1px solid #f1f5f9;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

tr.data-row:last-child td {
  border-bottom: none;
}

tr.data-row:hover {
  background: #f8fafc;
}

td.td-view {
  text-align: center;
}

.badge {
  display: inline-block;
  padding: 3px 10px;
  border-radius: 6px;
  font-size: 12px;
  font-weight: 600;
}

.b-yes {
  background: #dcfce7;
  color: #15803d;
}

.b-pending {
  background: #fef3c7;
  color: #92400e;
}

.b-no {
  background: #fee2e2;
  color: #991b1b;
}

.b-default {
  background: #f1f5f9;
  color: #64748b;
}

.expiry-ok {
  color: #15803d;
  font-weight: 500;
}

.expiry-soon {
  color: #92400e;
  font-weight: 500;
}

.expiry-expired {
  color: #991b1b;
  font-weight: 500;
}

.view-btn {
  background: #1A5C3A;
  border: none;
  border-radius: 50%;
  width: 28px;
  height: 28px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  color: #fff;
  transition: background 0.15s;
}

.view-btn:hover {
  background: #0f3d25;
