const MSA_CONFIG = {
  'Yes': {
    pillKey: 'yes',
    badgeClass: 'b-yes'
  },
  'Pending': {
    pillKey: 'pending',
    badgeClass: 'b-pending'
  },
  'No': {
    pillKey: 'no',
    badgeClass: 'b-no'
  }
};
const MSA_ORDER = ['Yes', 'Pending', 'No'];
let allData = [];
let activeMsa = 'All';
function initData() {
  const model = appsmith.model || {};
  allData = Array.isArray(model.customers) ? model.customers : [];
  window.applyFilters();
}
function formatDate(dateStr) {
  if (!dateStr) return '';
  const d = new Date(dateStr);
  if (isNaN(d)) return dateStr;
  return d.toLocaleDateString('en-GB', {
    day: 'numeric',
    month: 'short',
    year: 'numeric'
  });
}
function expiryClass(dateStr) {
  if (!dateStr) return '';
  const d = new Date(dateStr);
  const now = new Date();
  const diff = (d - now) / (1000 * 60 * 60 * 24);
  if (diff < 0) return 'expiry-expired';
  if (diff <= 30) return 'expiry-soon';
  return 'expiry-ok';
}
function buildPills() {
  const container = document.getElementById('filterPills');
  const presentMsa = MSA_ORDER.filter(s => allData.some(r => (r.msa_signed || '') === s));
  let html = '<span class="pill ' + (activeMsa === 'All' ? 'active-all' : '') + '" onclick="setMsaFilter(\'All\')">All <span class="cnt">' + allData.length + '</span></span>';
  presentMsa.forEach(function (s) {
    const cfg = MSA_CONFIG[s];
    const count = allData.filter(r => (r.msa_signed || '') === s).length;
    const isActive = activeMsa === s ? 'active-' + cfg.pillKey : '';
    html += '<span class="pill ' + isActive + '" onclick="setMsaFilter(\'' + s + '\')">' + s + ' <span class="cnt">' + count + '</span></span>';
  });
  container.innerHTML = html;
}
function renderTable(data) {
  const tbody = document.getElementById('tableBody');
  const noResults = document.getElementById('noResults');
  if (!data.length) {
    tbody.innerHTML = '';
    noResults.style.display = 'block';
    return;
  }
  noResults.style.display = 'none';
  tbody.innerHTML = data.map(function (row) {
    const name = row.customer_name || '';
    const dialRef = row.dial_ref || '';
    const expiry = row.dial_expiry || '';
    const msa = row.msa_signed || '';
    const created = row.created_at || '';
    const manager = row.account_manager || '';
    const id = row.customer_id;
    const msaCfg = MSA_CONFIG[msa] || {
      badgeClass: 'b-default'
    };
    const eCls = expiryClass(expiry);
    return '<tr class="data-row">' + '<td title="' + escHtml(name) + '">' + escHtml(name) + '</td>' + '<td>' + escHtml(dialRef) + '</td>' + '<td class="' + eCls + '">' + formatDate(expiry) + '</td>' + '<td><span class="badge ' + msaCfg.badgeClass + '">' + escHtml(msa || '—') + '</span></td>' + '<td>' + formatDate(created) + '</td>' + '<td title="' + escHtml(manager) + '">' + escHtml(manager) + '</td>' + '<td class="td-view"><button class="view-btn" onclick="viewCustomer(' + JSON.stringify(id) + ')" aria-label="View customer">' + '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round">' + '<line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>' + '</button></td></tr>';
  }).join('');
}
function escHtml(str) {
  return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
window.applyFilters = function () {
  const q = (document.getElementById('searchInput').value || '').toLowerCase();
  let filtered = allData;
  if (activeMsa !== 'All') filtered = filtered.filter(r => (r.msa_signed || '') === activeMsa);
  if (q) {
    filtered = filtered.filter(r => (r.customer_name || '').toLowerCase().includes(q) || (r.dial_ref || '').toLowerCase().includes(q) || (r.account_manager || '').toLowerCase().includes(q) || (r.msa_signed || '').toLowerCase().includes(q));
  }
  buildPills();
  renderTable(filtered);
};
window.setMsaFilter = function (val) {
  activeMsa = val;
  window.applyFilters();
};
window.viewCustomer = function (id) {
  appsmith.updateModel({
    customerId: id
  });
  appsmith.triggerEvent('onViewCustomer');
};
appsmith.onReady(function () {
  initData();
  appsmith.onModelChange(initData);
});

